module RefModule (  
    input wire clk,  
    input wire rst,  
    output reg [63:0] count  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            count <= 64'b0;  
        else  
            count <= count + 1;  
    end  
endmodule
